                style={{animationDelay: `${index * 0.05}s`}}
                onClick={() => onSelect(wf)}
              >
                <div className="card-top">
                  <div>
                    <h3 className="wf-name">{wf.name}</h3>
                    <div className="wf-id">ID: {wf.workflow_id.slice(0, 8)}...</div>
                  </div>
