          gap: 24px;
          padding: 12px 16px;
          background: rgba(15, 23, 42, 0.3);
          border-radius: 12px;
        }

        .stat {
          display: flex;
          flex-direction: column;
        }

        .stat-label {
          font-size: 10px;
          color: var(--muted);
          text-transform: uppercase;
          font-weight: 600;
        }

        .stat-value {
          font-size: 14px;
          font-weight: 700;
        }

        .card-actions {
          display: flex;
          align-items: center;
          gap: 12px;
          margin-top: auto;
        }

        .action-btn {
          width: 36px;
          height: 36px;
          display: flex;
          align-items: center;
          justify-content: center;
          border-radius: 10px;
          border: 1px solid var(--border);
          background: transparent;
          cursor: pointer;
          transition: all 0.2s;
        }

        .action-btn:hover {
          background: rgba(255, 255, 255, 0.05);
          transform: scale(1.05);
