        .action-btn.delete:hover { border-color: var(--danger); color: var(--danger); }
        .action-btn.edit:hover { border-color: var(--accent); color: var(--accent); }

        .pagination {
          margin-top: 40px;
          display: flex;
          align-items: center;
          justify-content: center;
          gap: 24px;
