        .page-btn:not(:disabled):hover {
          border-color: var(--accent);
          background: rgba(99, 102, 241, 0.1);
        }

        .page-info {
          font-size: 14px;
          color: var(--muted);
        }

        .loading-state {
          text-align: center;
          padding: 80px;
          display: flex;
          flex-direction: column;
          align-items: center;
          gap: 16px;
